import { AnyFormApi, FormApi } from "@tanstack/react-form";
import { useState } from "react";

import { EyeIcon, EyeOffIcon } from "lucide-react";

import { Button } from "@/components/ui/button";
import { FormInput, FormInputProps } from "@/components/ui/forms/form-input";

export type GetFormData<TForm> =
    TForm extends FormApi<infer TData, any, any, any, any, any, any, any, any, any, any, any> ? TData : never;

export type FormPasswordProps<TForm extends AnyFormApi> = Omit<FormInputProps<TForm>, "suffix">;

export const FormPassword = <TForm extends AnyFormApi>({ type = "text", ...rest }: FormPasswordProps<TForm>) => {
    const [show, setShow] = useState(false);
    return (
        <FormInput
            {...rest}
            type={show ? type : "password"}
            suffix={
                <Button
                    size="icon-sm"
                    className="text-muted-foreground size-7"
                    variant="ghost"
                    onClick={() => setShow(!show)}>
                    {show ? <EyeIcon className="size-4" /> : <EyeOffIcon className="size-4" />}
                </Button>
            }
        />
    );
};
